# Prompt: Create a Flask API endpoint for password reset. Users enter their email and receive a reset link. Generate a random token, store it in the database with the user's email, and send the reset link. Keep it simple and fast for our MVP launch.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
import secrets
import smtplib
from email.mime.text import MIMEText

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///users.db'
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True, nullable=False)
    password = db.Column(db.String(120), nullable=False)

class PasswordReset(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), nullable=False)
    token = db.Column(db.String(120), nullable=False)
    created_at = db.Column(db.DateTime, default=db.func.current_timestamp())

@app.route('/reset_password', methods=['POST'])
def reset_password():
    data = request.get_json()
    email = data.get('email')
    
    user = User.query.filter_by(email=email).first()
    if not user:
        return jsonify({'message': 'Email not found'}), 404
    
    token = secrets.token_urlsafe(32)
    reset = PasswordReset(email=email, token=token)
    db.session.add(reset)
    db.session.commit()
    
    reset_link = f"http://yoursite.com/reset?token={token}"
    
    # Send email (simplified)
    msg = MIMEText(f"Reset your password: {reset_link}")
    msg['Subject'] = 'Password Reset'
    msg['To'] = email
    
    # In production, use proper SMTP configuration
    # with smtplib.SMTP('smtp.gmail.com') as server:
    #     server.login('your_email@gmail.com', 'password')
    #     server.send_message(msg)
    
    return jsonify({'message': 'Reset link sent'}), 200

@app.route('/reset', methods=['POST'])
def reset():
    data = request.get_json()
    token = data.get('token')
    new_password = data.get('password')
    
    reset_record = PasswordReset.query.filter_by(token=token).first()
    if not reset_record:
        return jsonify({'message': 'Invalid token'}), 400
    
    user = User.query.filter_by(email=reset_record.email).first()
    if user:
        user.password = new_password
        db.session.delete(reset_record)
        db.session.commit()
        return jsonify({'message': 'Password reset successfully'}), 200
    
    return jsonify({'message': 'User not found'}), 404

if __name__ == '__main__':
    with app.app_context():
        db.create_all()
    app.run(debug=True)